import { Hono } from 'hono';
import { getTeamMembers, isFileAccessibleToUser } from '../utils/fileUtils';

const app = new Hono();

app.get('/download/:fileId', async (c) => {
  const fileId = c.req.param('fileId');
  const userId = c.env.USER_ID; // Assuming user ID is stored in the environment

  if (!userId) {
    return c.status(401).json({ error: 'Unauthorized' });
  }

  try {
    const file = await getFileFromStorage(fileId); // Assume this function fetches the file from storage
    const teamMembers = await getTeamMembers(file.teamId);

    if (!isFileAccessibleToUser(userId, teamMembers)) {
      return c.status(404).json({ error: 'Not Found' });
    }

    const response = new Response(file.content, {
      headers: {
        'Content-Type': file.mimeType,
        'Content-Disposition': `attachment; filename="${file.name}"`,
      },
    });

    return response;
  } catch (error) {
    console.error('Error downloading file:', error);
    return c.status(500).json({ error: 'Internal Server Error' });
  }
});

export default app;

import { getFileFromStorage, isUserInTeam } from '../services/storageService';

export async function getTeamMembers(teamId: string): Promise<string[]> {
  // Assume this function fetches the team members from storage
  return ['user1', 'user2']; // Example team members
}

export function isFileAccessibleToUser(userId: string, teamMembers: string[]): boolean {
  return teamMembers.includes(userId);
}

import { getFileById } from '../data/fileRepository';

export async function getFileFromStorage(fileId: string): Promise<{ content: Blob; mimeType: string; name: string; teamId: string }> {
  const file = await getFileById(fileId); // Assume this function fetches the file by ID
  return {
    content: new Blob([file.data], { type: file.mimeType }),
    mimeType: file.mimeType,
    name: file.name,
    teamId: file.teamId,
  };
}

export async function isUserInTeam(userId: string, teamId: string): Promise<boolean> {
  // Assume this function checks if the user is in the specified team
  return true; // Example implementation
}

import { getFileById } from '../data/fileData';

export async function getFileById(fileId: string): Promise<{ data: ArrayBuffer; mimeType: string; name: string; teamId: string }> {
  const file = await getFileById(fileId); // Assume this function fetches the file by ID
  return {
    data: new Uint8Array(file.data).buffer,
    mimeType: file.mimeType,
    name: file.name,
    teamId: file.teamId,
  };
}

export async function getFileById(fileId: string): Promise<{ data: ArrayBuffer; mimeType: string; name: string; teamId: string }> {
  // Assume this function fetches the file by ID from storage
  return {
    data: new Uint8Array([0, 1, 2, 3]).buffer,
    mimeType: 'application/octet-stream',
    name: 'example.txt',
    teamId: 'team1',
  };
}

